// Cleanup service worker for visitors who still have Chirpy's old PWA cache.
// jekyll-dash does not use a service worker, so this worker clears legacy
// caches, reloads controlled pages from the network, then unregisters itself.
(function () {
  "use strict";

  var CLEANUP_VERSION = "laggy-blog-chirpy-cleanup-2026-05-05";

  async function deleteAllCaches() {
    if (!self.caches) {
      return;
    }

    var keys = await caches.keys();
    await Promise.all(
      keys.map(function (key) {
        return caches.delete(key);
      })
    );
  }

  async function refreshWindows() {
    var windowClients = await self.clients.matchAll({
      type: "window",
      includeUncontrolled: true
    });

    await Promise.all(
      windowClients.map(function (client) {
        client.postMessage({
          type: "SW_CLEANUP_DONE",
          version: CLEANUP_VERSION
        });

        if ("navigate" in client && client.url) {
          return client.navigate(client.url);
        }

        return undefined;
      })
    );
  }

  self.addEventListener("install", function (event) {
    event.waitUntil(self.skipWaiting());
  });

  self.addEventListener("activate", function (event) {
    event.waitUntil(
      (async function () {
        await deleteAllCaches();
        await self.clients.claim();
        await refreshWindows();
        await self.registration.unregister();
      })()
    );
  });

  self.addEventListener("message", function (event) {
    if (event.data === "SKIP_WAITING") {
      self.skipWaiting();
    }
  });

  self.addEventListener("fetch", function (event) {
    if (event.request.method !== "GET") {
      return;
    }

    event.respondWith(fetch(event.request, { cache: "reload" }));
  });
})();
